import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { getPlayroomById } from "../services/playroomService";
import { getTimeSlots, createBooking } from "../services/bookingService";
import { useAuth } from "../context/AuthContext";
import "../styles/Book.css";

const Book = () => {
  const { id } = useParams();
  const { user, isAuthenticated } = useAuth();
  const navigate = useNavigate();

  const [playroom, setPlayroom] = useState(null);
  const [timeSlots, setTimeSlots] = useState([]);
  const [selectedSlot, setSelectedSlot] = useState(null);
  const [brojDece, setBrojDece] = useState(1);
  const [napomena, setNapomena] = useState("");
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [selectedDate, setSelectedDate] = useState(
    new Date().toISOString().split("T")[0],
  );

  useEffect(() => {
    if (!isAuthenticated) {
      navigate("/login");
      return;
    }
    loadData();
  }, [id, selectedDate]);

  const loadData = async () => {
    setLoading(true);
    const playroomResult = await getPlayroomById(id);
    if (playroomResult.success) {
      setPlayroom(playroomResult.data);
    }

    const slotsResult = await getTimeSlots(id, selectedDate);
    if (slotsResult.success) {
      setTimeSlots(slotsResult.data);
    }

    setLoading(false);
  };

  const handleBook = async () => {
    if (!selectedSlot) {
      setError("Izaberite termin");
      return;
    }

    setSubmitting(true);
    setError("");

    const result = await createBooking({
      timeSlotId: selectedSlot._id,
      brojDece,
      napomena,
    });

    if (result.success) {
      navigate("/my-bookings");
    } else {
      setError(result.error);
    }
    setSubmitting(false);
  };

  if (loading) {
    return <div className="container loading">Učitavanje...</div>;
  }

  if (!playroom) {
    return <div className="container">Igraonica nije pronađena</div>;
  }

  return (
    <div className="container book-page">
      <button className="btn-back" onClick={() => navigate(`/playrooms/${id}`)}>
        ← Nazad na igraonicu
      </button>

      <div className="book-card">
        <h1>Rezerviši termin</h1>
        <h2>{playroom.naziv}</h2>
        <p className="book-location">
          📍 {playroom.adresa}, {playroom.grad}
        </p>

        {error && <div className="error-message">{error}</div>}

        <div className="form-group">
          <label>Izaberite datum</label>
          <input
            type="date"
            value={selectedDate}
            onChange={(e) => setSelectedDate(e.target.value)}
            min={new Date().toISOString().split("T")[0]}
          />
        </div>

        <div className="form-group">
          <label>Izaberite termin</label>
          {timeSlots.length === 0 ? (
            <p className="no-slots">Nema slobodnih termina za izabrani datum</p>
          ) : (
            <div className="time-slots-grid">
              {timeSlots.map((slot) => (
                <div
                  key={slot._id}
                  className={`time-slot ${selectedSlot?._id === slot._id ? "selected" : ""} ${slot.slobodno === 0 ? "full" : ""}`}
                  onClick={() => slot.slobodno > 0 && setSelectedSlot(slot)}
                >
                  <div className="time-slot-time">
                    {slot.vremeOd} - {slot.vremeDo}
                  </div>
                  <div className="time-slot-info">
                    <span>💰 {slot.cena} RSD/dete</span>
                    <span>
                      👥 {slot.slobodno}/{slot.maxDece} slobodno
                    </span>
                  </div>
                  {slot.slobodno === 0 && (
                    <div className="full-badge">POPUNJENO</div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>

        {selectedSlot && (
          <>
            <div className="form-group">
              <label>Broj dece</label>
              <input
                type="number"
                min="1"
                max={selectedSlot.slobodno}
                value={brojDece}
                onChange={(e) =>
                  setBrojDece(
                    Math.min(
                      selectedSlot.slobodno,
                      parseInt(e.target.value) || 1,
                    ),
                  )
                }
              />
            </div>

            <div className="form-group">
              <label>Napomena (opciono)</label>
              <textarea
                rows="3"
                value={napomena}
                onChange={(e) => setNapomena(e.target.value)}
                placeholder="Npr. alergije, posebni zahtevi..."
              />
            </div>

            <div className="price-summary">
              <h3>Ukupno za plaćanje</h3>
              <div className="price-details">
                <span>
                  {brojDece} dete × {selectedSlot.cena} RSD
                </span>
                <strong>= {brojDece * selectedSlot.cena} RSD</strong>
              </div>
            </div>
          </>
        )}

        <button
          className="btn-book-final"
          onClick={handleBook}
          disabled={submitting || !selectedSlot || selectedSlot.slobodno === 0}
        >
          {submitting ? "Rezervišem..." : "Rezerviši"}
        </button>
      </div>
    </div>
  );
};

export default Book;
